def simple_module_source():
    return textwrap.dedent(
        '''
        """Example module docstring."""
        import os
        import sys
        from math import sqrt


        def add(a, b):
            """Add two numbers."""
            return a + b


        def subtract(a, b):
            """Subtract two numbers."""
            return a - b
        '''
    ).lstrip()

def class_source():
    return textwrap.dedent(
        '''
        """Geometry helpers."""
        from math import pi


        class Shape:
            """Base shape."""

            kind = "shape"

            def __init__(self, name: str) -> None:
                self.name = name

            def describe(self) -> str:
                return f"shape {self.name}"


        class Circle(Shape, metaclass=type):
            """A circle."""

            def __init__(self, r: float) -> None:
                super().__init__("circle")
                self.r = r

            @staticmethod
            def pi_value() -> float:
                return pi

            @classmethod
            def unit(cls) -> "Circle":
                return cls(1.0)

            def area(self) -> float:
                return pi * self.r * self.r
        '''
    ).lstrip()

