def linear_graph():
    """Linear graph: a -> b -> c -> d"""
    nodes = pd.DataFrame({
        'id': ['a', 'b', 'c', 'd'],
        'type': ['start', 'mid', 'mid', 'end'],
        'value': [0, 1, 2, 3]
    })
    edges = pd.DataFrame({
        'src': ['a', 'b', 'c'],
        'dst': ['b', 'c', 'd'],
        'eid': [0, 1, 2],
        'weight': [1.0, 2.0, 3.0]
    })
    return CGFull().nodes(nodes, 'id').edges(edges, 'src', 'dst', edge='eid')

def branching_graph():
    """Branching graph: a -> b, a -> c, b -> d, c -> d"""
    nodes = pd.DataFrame({
        'id': ['a', 'b', 'c', 'd'],
        'type': ['root', 'left', 'right', 'sink'],
        'value': [0, 1, 2, 3]
    })
    edges = pd.DataFrame({
        'src': ['a', 'a', 'b', 'c'],
        'dst': ['b', 'c', 'd', 'd'],
        'eid': [0, 1, 2, 3],
        'branch': ['left', 'right', 'left', 'right']
    })
    return CGFull().nodes(nodes, 'id').edges(edges, 'src', 'dst', edge='eid')

def cyclic_graph():
    """Cyclic graph: a -> b -> c -> a"""
    nodes = pd.DataFrame({
        'id': ['a', 'b', 'c'],
        'value': [0, 1, 2]
    })
    edges = pd.DataFrame({
        'src': ['a', 'b', 'c'],
        'dst': ['b', 'c', 'a'],
        'eid': [0, 1, 2]
    })
    return CGFull().nodes(nodes, 'id').edges(edges, 'src', 'dst', edge='eid')

def disconnected_graph():
    """Disconnected graph: (a -> b) and (c -> d) with no connection"""
    nodes = pd.DataFrame({
        'id': ['a', 'b', 'c', 'd'],
        'component': [1, 1, 2, 2]
    })
    edges = pd.DataFrame({
        'src': ['a', 'c'],
        'dst': ['b', 'd'],
        'eid': [0, 1]
    })
    return CGFull().nodes(nodes, 'id').edges(edges, 'src', 'dst', edge='eid')

def self_loop_graph():
    """Graph with self-loop: a -> a, a -> b"""
    nodes = pd.DataFrame({
        'id': ['a', 'b'],
        'value': [0, 1]
    })
    edges = pd.DataFrame({
        'src': ['a', 'a'],
        'dst': ['a', 'b'],
        'eid': [0, 1]
    })
    return CGFull().nodes(nodes, 'id').edges(edges, 'src', 'dst', edge='eid')

def parallel_edges_graph():
    """Graph with parallel edges: a -> b (twice)"""
    nodes = pd.DataFrame({
        'id': ['a', 'b'],
        'value': [0, 1]
    })
    edges = pd.DataFrame({
        'src': ['a', 'a'],
        'dst': ['b', 'b'],
        'eid': [0, 1],
        'label': ['first', 'second']
    })
    return CGFull().nodes(nodes, 'id').edges(edges, 'src', 'dst', edge='eid')

def linear_graph():
    """Linear graph: a -> b -> c -> d"""
    nodes = pd.DataFrame({'id': ['a', 'b', 'c', 'd']})
    edges = pd.DataFrame({
        'src': ['a', 'b', 'c'],
        'dst': ['b', 'c', 'd'],
        'eid': [0, 1, 2],
    })
    return graphistry.nodes(nodes, 'id').edges(edges, 'src', 'dst')

