        "presets": {
            "bf16": {
                "params": 2,
                "kv_cache": 2,
                "ssm_cache": 2,
                "max_buffer": 2,
                "param_budget_target": "active",
            },
            "fp8_kv": {
                "params": 2,
                "kv_cache": 1,
                "ssm_cache": 2,
                "max_buffer": 2,
                "param_budget_target": "active",
            },
            "total_target": {
                "params": 2,
                "kv_cache": 2,
                "ssm_cache": 2,
                "max_buffer": 2,
                "param_budget_target": "total",
            },
        }
    }
    path = tmp_path / "memory_profiles.yaml"
    path.write_text(yaml.safe_dump(data))
    return str(path)

