        {
            "timestamp": base_time,
            "team_id": 1,
            "event": "$ai_generation",
            "properties": {
                "$ai_trace_id": "trace-2",
                "$ai_session_id": "session-1",
                "$ai_error": "",
            },
        },
        # Team 1: 2 spans from same trace
        {
            "timestamp": base_time,
            "team_id": 1,
            "event": "$ai_span",
            "properties": {
                "$ai_trace_id": "trace-1",
                "$ai_session_id": "session-1",
                "$ai_is_error": True,
            },
        },
        {
            "timestamp": base_time,
            "team_id": 1,
            "event": "$ai_span",
            "properties": {
                "$ai_trace_id": "trace-1",
                "$ai_session_id": "session-1",
                "$ai_is_error": False,
            },
        },
        # Team 2: 1 generation, no errors
        {
            "timestamp": base_time,
            "team_id": 2,
            "event": "$ai_generation",
            "properties": {
                "$ai_trace_id": "trace-3",
                "$ai_session_id": "session-2",
                "$ai_error": "",
            },
        },
        # Team 1: Pageviews on LLM Analytics
        {
            "timestamp": base_time,
            "team_id": 1,
            "event": "$pageview",
            "properties": {
                "$current_url": "https://app.posthog.com/project/123/llm-analytics/traces?filter=active",
