def fake_redis() -> Generator[fakeredis.FakeRedis]:
    client = fakeredis.FakeRedis()

    @contextmanager
    def _fake_client():
        yield client

    with patch.object(sync_lock, "_get_redis_client", _fake_client):
        yield client

