def wide_parquet(self, tmp_path):
        import os

        path = os.path.join(str(tmp_path), "wide.parquet")
        pq.write_table(
            pa.table(
                {
                    "k": [i % 3 for i in range(60)],
                    "a": [float(i) for i in range(60)],
                    "b": [0.5] * 60,
                    "unused": ["x" * 32] * 60,  # wide column nothing consumes
                }
            ),
            path,
        )
        return path

